import React, { useState } from 'react';
import { useAuth } from './AuthContext';
import LoginModal from './LoginModal';
import RegisterModal from './RegisterModal';
import CartModal from './CartModal';
import './Header.css';

const Header = () => {
    const [showLogin, setShowLogin] = useState(false);
    const [showRegister, setShowRegister] = useState(false);
    const [showCart, setShowCart] = useState(false);
    const { user, logout } = useAuth();

    return (
        <>
            <header>
                <div className="container">
                    <nav>
                        <div className="logo">
                            <a href="/">
                                <h1>Auto<span>Vip</span></h1>
                            </a>
                        </div>
                        
                        <ul className="nav-menu">
                            <li><a href="/">Trang Chủ</a></li>
                            <li><a href="#cars">Xe</a></li>
                            <li><a href="#brands">Thương Hiệu</a></li>
                            {user && user.role === 'admin' && (
                                <li><a href="/admin">Quản Lý</a></li>
                            )}
                        </ul>
                        
                        <div className="nav-buttons">
                            {user && (
                                <button onClick={() => setShowCart(true)} className="cart-icon">
                                    🛒
                                </button>
                            )}
                            
                            {user ? (
                                <>
                                    <a href="/profile" className="profile-btn">
                                        <svg className="profile-icon" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                            <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"></path>
                                            <circle cx="12" cy="7" r="4"></circle>
                                        </svg>
                                        Cá Nhân
                                    </a>
                                    
                                    <div className="user-info">
                                        <span className="welcome-text">
                                            👋 {user.fullname}
                                        </span>
                                        <button onClick={logout} className="logout-btn">
                                            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                                <path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"></path>
                                                <polyline points="16 17 21 12 16 7"></polyline>
                                                <line x1="21" y1="12" x2="9" y2="12"></line>
                                            </svg>
                                            Đăng xuất
                                        </button>
                                    </div>
                                </>
                            ) : (
                                <>
                                    <button onClick={() => setShowLogin(true)} className="btn-login">
                                        Đăng Nhập
                                    </button>
                                    <button onClick={() => setShowRegister(true)} className="btn-register">
                                        Đăng Ký
                                    </button>
                                </>
                            )}
                        </div>
                    </nav>
                </div>
            </header>

            <LoginModal 
                isOpen={showLogin}
                onClose={() => setShowLogin(false)}
                onSwitchToRegister={() => {
                    setShowLogin(false);
                    setShowRegister(true);
                }}
            />

            <RegisterModal 
                isOpen={showRegister}
                onClose={() => setShowRegister(false)}
                onSwitchToLogin={() => {
                    setShowRegister(false);
                    setShowLogin(true);
                }}
            />

            <CartModal 
                isOpen={showCart}
                onClose={() => setShowCart(false)}
            />
        </>
    );
};

export default Header;
